class ODT {
private:
	struct ODT_Node {
		int l, r;
		mutable ll v; // 从 v 开始的等差数列

		// 重载小于号以用于 set 排序
		bool operator<(const ODT_Node& a)const {
			return l < a.l;
		}
	};

	// ODT 的核心操作：分裂区间
	// 将包含 pos 的区间 [l, r] 分裂为 [l, pos - 1] 和 [pos, r]
	// 返回指向后半段 [pos, r] 的迭代器
	auto split(int pos) {
		auto it = se.lower_bound({ pos, 0, 0 });
		if (it != se.end() and it->l == pos)return it;

		it = prev(it);
		auto [l, r, v] = *it;
		se.erase(it);
		se.insert({ l, pos - 1, v });

		return se.insert({ pos, r, v }).first;
	}

public:
	set<ODT_Node> se;

	// 区间加值（不会推平）
	void assign1(int l, int r, ll v) {
		auto itr = split(r + 1);
		auto itl = split(l);

		// 遍历 [itl, itr) 之间的所有区间
		auto it = itl;
		while (it != itr) {
			it->v += v;
			it = next(it);
		}
	}

	// 区间赋值（推平）
	void assign2(int l, int r, ll v) {
		auto itr = split(r + 1);
		auto itl = split(l);

		// 遍历 [itl, itr) 之间的所有区间
		auto it = itl;
		while (it != itr) {
			auto [l, r, v] = *it;
			it = se.erase(it); // 删除旧区间
		}

		// 插入新区间
		se.insert({ l, r, v });
	}

	ll query1(int l, int r, ll x) {
		auto itr = split(r + 1);
		auto itl = split(l);

		var mp = map<ll, ll>();
		auto it = itl;
		while (it != itr) {
			auto [l, r, v] = *it;
			mp[v] += r - l + 1;
			it = next(it);
		}

		ll now = 0;
		for (const var& [v, cnt] : mp) {
			now += cnt;
			if (now >= x)return v;
		}
	}

	ll query2(int l, int r, ll x, ll y) {
		auto itr = split(r + 1);
		auto itl = split(l);

		ll res = 0;
		auto it = itl;
		while (it != itr) {
			auto [l, r, v] = *it;
			res = (res + Math::fastPow(v, x, y) * (r - l + 1ll) % y) % y;
			it = next(it);
		}

		return res;
	}
};

ll rnd(ll& seed) {
	ll res = seed;
	seed = (seed * 7 + 13) % 1000000007;
	return res;
}
void solve(int CASE)
{
	ll n, q, seed, vmax; cin >> n >> q >> seed >> vmax;
	ODT odt;
	fa(i, 1, n) {
		ll v = rnd(seed) % vmax + 1;
		odt.se.insert({ i, i, v });
	}
	while (q--) {
		ll op = rnd(seed) % 4 + 1;
		ll l = rnd(seed) % n + 1;
		ll r = rnd(seed) % n + 1;
		if (l > r)swap(l, r);

		if (op == 1) {
			ll x = rnd(seed) % vmax + 1;
			odt.assign1(l, r, x);
		}
		else if (op == 2) {
			ll x = rnd(seed) % vmax + 1;
			// 操作 2 对节点进行均摊
			odt.assign2(l, r, x);
		}
		else if (op == 3) {
			ll x = rnd(seed) % (r - l + 1) + 1;
			cout << odt.query1(l, r, x) << endl;
		}
		else {
			ll x = rnd(seed) % vmax + 1;
			ll y = rnd(seed) % vmax + 1;
			cout << odt.query2(l, r, x, y) << endl;
		}
	}
	return;
}
